.darma-loader-darma-custom-675 {
  color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: var(--loader-secondary-color, #67e8f9);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: 1;
--c: no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0% 50%,
var(--c) 50% 50%,
var(--c) 100% 50%;
background-size: 20% 100%;
animation: darma-loader-darma-custom-675-l1 1s infinite linear;
}
@keyframes darma-loader-darma-custom-675-l1 {
0% {background-size: 20% 100%,20% 100%,20% 100%}
33% {background-size: 20% 10% ,20% 100%,20% 100%}
50% {background-size: 20% 100%,20% 10% ,20% 100%}
66% {background-size: 20% 100%,20% 100%,20% 10% }
100%{background-size: 20% 100%,20% 100%,20% 100%}
}

